function monteCarloPi(points) {
    let insideCircle = 0;
    for (let i = 0; i < points; i++) {
        const x = Math.random() * 2 - 1;
        const y = Math.random() * 2 - 1;
        if (x*x + y*y <= 1) {
            insideCircle++;
        }
    }
    return 4 * insideCircle / points;
}

// Nümunə: π dəyərinin təxmini hesablanması
const points = 100000;
const piEstimate = monteCarloPi(points);
console.log(`Estimated Pi: ${piEstimate}`);
